class Observer {
public:
    virtual void update(int v) = 0;
    virtual ~Observer() = default;
};

class Subject {
    vector<Observer*> observers;
    int value = 0;
public:
    void attach(Observer* o) { observers.push_back(o); }
    void setValue(int v) {
        value = v;
        for (auto o : observers) o->update(value);
    }
};

class Display : public Observer {
public:
    void update(int v) override { cout << v; }
};

int main() {
    Subject s;
    Display d;
    s.attach(&d);
    s.setValue(42);
    return 0;
}

