#include <iostream>
using namespace std;

class Handler {
protected:
    Handler* next = nullptr;
public:
    void setNext(Handler* n) { next = n; }
    virtual void handle(int r) {
        if (next) next->handle(r);
    }
    virtual ~Handler() = default;
};

class ConcreteHandler : public Handler {
    int level;
public:
    ConcreteHandler(int l) : level(l) {}
    void handle(int r) override {
        if (r <= level) cout << level;
        else Handler::handle(r);
    }
};

int main() {
    ConcreteHandler h1(1), h2(5), h3(10);
    h1.setNext(&h2);
    h2.setNext(&h3);
    h1.handle(3);
    return 0;
}

