template<typename T>
void forward_call(T&& arg) {
    process(forward<T>(arg));
}

int main() {
    int x = 5;
    forward_call(x);
    forward_call(10);
    return 0;
}

#include <iostream>
#include <utility>
using namespace std;

class Base {
public:
    virtual void print() { cout << "B"; }
    Base() = default;
    Base(Base&&) { cout << "Moved"; }
};

class Derived : public Base {
public:
    void print() override { cout << "D"; }
};

int main() {
    Derived d;
    Derived d2 = move(d);
    d2.print();
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Base {
public:
    virtual void show() { cout << "Base"; }
    virtual ~Base() = default;
};

class Derived : public Base {
public:
    void show() override { cout << "Derived"; }
};

int main() {
    unique_ptr<Base> p = make_unique<Derived>();
    p->show();
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Base {
public:
    virtual void greet() { cout << "Hi"; }
    virtual ~Base() = default;
};

class Derived : public Base {
public:
    void greet() override { cout << "Hello"; }
};

int main() {
    shared_ptr<Base> p1 = make_shared<Derived>();
    shared_ptr<Base> p2 = p1;
    p2->greet();
    return 0;
}
